local CS = CS

local _GameObject = UnityEngine.GameObject
local _Object = UnityEngine.Object

---@param uObj UnityEngine.Object
function IsNull(uObj)
	return uObj == nil or uObj:Equals(nil)
end
---@param uObj UnityEngine.Object
function IsValid(uObj)
	return not IsNull(uObj)
end

function FindObject(path)
	return _GameObject.Find(path)
end
--- 传入名字（路径也可以），查找子孙节点
---@param trans Transform
---@param nodeName string
function FindChild(trans, nodeName)
	if IsNull(trans) then
		return nil
	end
	local child = trans:Find(nodeName)
	if child then
		return child
	end

	local childCount = trans.childCount
	for i = 1, childCount do
		child = FindChild(trans:GetChild(i-1), nodeName)
		if IsValid(child) then
			return child
		end
	end
	return child
end

function NewGameObject(name)
	return _GameObject.New(name)
end

--创建一个对象--
function NewObject(prefab)
	return _Object.Instantiate(prefab)
end

-- 克隆一个gameObject
function InstantObject(gameObject)
	return _GameObject.Instantiate(gameObject)
end

function ShowObject(go, bShow)
	if IsNull(go) then
		return
	end
	return go:SetActive(bShow)
end

function ShowTrans(trans, bShow)
	if IsNull(trans) then
		return
	end
	return trans.gameObject:SetActive(bShow)
end

function ShowAllChild(go, bShow)
	if IsNull(go) then
		return
	end
	local trans = go.transform
	if trans.childCount > 0 then
		for i = 1, trans.childCount do
			ShowObject(trans:GetChild(i-1).gameObject, bShow)
		end
	end
end

--销毁一个对象
function DestroyObject(obj)
	if IsNull(obj) then
		return
	end
	_Object.Destroy(obj)
end

--销毁子对象
function DestroyAllChild(obj)
	local trans = obj.transform
	if trans.childCount > 0 then
		for i = 1, trans.childCount do
			DestroyObject(trans:GetChild(0).gameObject)
		end
	end
end

function InvokeCallback(cbFunc, cbObj, ...)
	if cbObj then
		cbFunc(cbObj, ...)
	else
		cbFunc(...)
	end
end


function FormatLogWithColor(s, color)
	local partList = string.split(s, '\n')
	local colorStart = string.format("<color=#%s>", color)
	local colorEnd = "</color>"
	local lines = {colorStart}
	for k,v in ipairs(partList) do
		if (k == 2) then
			table.insert(lines, v)
			table.insert(lines, colorEnd)
			table.insert(lines,"\n")
			table.insert(lines, colorStart)
		else
			table.insert(lines, v)
			table.insert(lines, "\n")
		end
	end
	table.insert(lines, colorEnd)
	return table.concat(lines)
end

