function GetTimestamp()
	local time
	local startTime = S_TIME_START
	local serverTime = S_SERVER_TIME
	if startTime and serverTime then
		time = serverTime + Time.realtimeSinceStartup - startTime
	end
	if not time then
		return os.time()
	else
		return time
	end
end

function GetTimezone()
	local serverTime = S_SERVER_TIME
	local timezone = S_TIME_ZONE
	if serverTime and timezone then
		return timezone
	end
	local now = os.time()
	local zone = os.difftime(now, os.time(os.date("!*t", now)))
	return zone
end

function GetServerDayPast(startTime)
	local serverTime = S_SERVER_TIME
	local timezone = S_TIME_ZONE

	if not serverTime or not timezone then
		return 1
	end
	local startDay = math.floor((startTime + timezone)/86400)
	local curTime = serverTime
	local curDay = math.floor((curTime + timezone)/86400)
	local dayPast = curDay - startDay + 1
	dayPast = math.max(dayPast,1)

	return dayPast
end

