local _printLngLog = function(textid, str)
	if LPlayerPrefs.openClientTextLog == "1" then
		printErrorN("## 富文本日志：~~~文本 id = "..textid.." | text = "..tostring(str))
	end
end

function ccClientText(textid, arg1, ...)
	if(gLGameI18n) then
		local str = gLGameI18n:I18nText(textid)
		if LOG_INFO_ENABLED then
			_printLngLog(textid, str)
		end
		if str then
			if arg1 then
				str = string.replace(str, arg1, ...)
			end
			return str
		end
	end
	return tostring(textid)
end

