function RestartGame()
	local restartType = 0
	if CS.IsWebGL() then
		if LWxHelper.IsMiniGamePlatform() then
			if LWxHelper.IsSupportRestartMiniProgram() then
				restartType = 1
			end
		else
			restartType = 2
		end
	end

	if restartType == 1 then
		LWxHelper.WxRestartMiniProgram()
	elseif restartType == 2 then
		LNativeHelper.CallMethod("RestartWebGLProgram")
	else
		if gLxRestartCtrl and gLxRestartCtrl:IsRestarting() then
			return
		end
		if LGameRunMode.IsLoading() then
			if gLGameScene then
				gLGameScene:SetChangeSceneRemainParams(LevelNames.Empty, {op = 1})
			end
			return
		end
		
		GF.ChangeToRestartScene()
	end
end

function ReLoginGame()
	local restartType = 0
	if CS.IsWebGL() then
		if LWxHelper.IsMiniGamePlatform() then
			if LWxHelper.IsSupportRestartMiniProgram() then
				restartType = 1
			end
		else
			restartType = 2
		end
	end

	if restartType == 1 then
		LWxHelper.WxRestartMiniProgram()
	elseif restartType == 2 then
		LNativeHelper.CallMethod("RestartWebGLProgram")
	else
		if gLxRestartCtrl and gLxRestartCtrl:IsRestarting() then
			return
		end

		if LGameRunMode.IsLoading() then
			if gLGameScene then
				gLGameScene:SetChangeSceneRemainParams(LevelNames.Empty, {op = 2})
			end
			return
		end

		GF.ChangeToReLoginScene()
	end
end

function QuitGame()
	if CS.IsWebGL() then
		LNativeHelper.CallMethod("Exit")
	else
		CS.QuitGame()
	end 
end